// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005

// Define the structure for a tree node
typedef struct Node {
    int have;
    int cap;
    int parent;
    int rogue;
} Node;

// Function to create a new tree node
Node* createNode(int have, int cap) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->have = have;
    node->cap = cap;
    node->parent = -1;
    node->rogue = 0;
    return node;
}

// Function to perform BFS traversal of the tree
void bfs(Node** nodes, int* bosses, int N) {
    int* queue = (int*) malloc(N * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = 0;

    while (front < rear) {
        int nodeIndex = queue[front++];
        Node* node = nodes[nodeIndex];

        // Update the have values of the node's children
        for (int i = 0; i < N; i++) {
            if (bosses[i] == nodeIndex) {
                Node* child = nodes[i];
                if (!child->rogue) {
                    node->have += child->have;
                    child->have = 0;
                }
            }
        }

        // Check if the node turns rogue
        if (node->have > node->cap) {
            node->rogue = 1;
        }

        // Add the node's parent to the queue
        if (node->parent != -1) {
            queue[rear++] = node->parent;
        }
    }

    free(queue);
}

int main() {
    int N;
    scanf("%d", &N);

    Node** nodes = (Node**) malloc(N * sizeof(Node*));
    int* bosses = (int*) malloc((N - 1) * sizeof(int));

    // Read the have and cap values for each node
    for (int i = 1; i < N; i++) {
        int have, cap;
        scanf("%d %d", &have, &cap);
        nodes[i] = createNode(have, cap);
    }

    // Read the boss for each node
    for (int i = 1; i < N; i++) {
        scanf("%d", &bosses[i - 1]);
        nodes[i]->parent = bosses[i - 1];
    }

    // Perform BFS traversal of the tree
    bfs(nodes, bosses, N);

    // Print the total amount present at the root node
    printf("%d\n", nodes[0]->have);

    // Free the memory allocated for the nodes and bosses
    for (int i = 0; i < N; i++) {
        free(nodes[i]);
    }
    free(nodes);
    free(bosses);

    return 0;
}

