import java.util.Queue;
import java.util.LinkedList;
public class Main {
    static class Node {
        int have;
        int cap;
        int parent;
        boolean rogue;

        public Node(int have, int cap) {
            this.have = have;
            this.cap = cap;
            this.parent = -1;
            this.rogue = false;
        }
    }

    // Function to perform BFS traversal of the tree
    public static void bfs(Node[] nodes, int[] bosses, int N) {
        Queue<Integer> q = new LinkedList<>();
        q.add(0);

        while (!q.isEmpty()) {
            int nodeIndex = q.poll();
            Node node = nodes[nodeIndex];

            // Update the have values of the node's children
            for (int i = 0; i < N; i++) {
                if (bosses[i] == nodeIndex) {
                    Node child = nodes[i];
                    if (!child.rogue) {
                        node.have += child.have;
                        child.have = 0;
                    }
                }
            }

            // Check if the node turns rogue
            if (node.have > node.cap) {
                node.rogue = true;
            }

            // Add the node's parent to the queue
            if (node.parent != -1) {
                q.add(node.parent);
            }
        }
    }

    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int N = sc.nextInt();

        Node[] nodes = new Node[N];
        int[] bosses = new int[N - 1];

        // Read the have and cap values for each node
        for (int i = 1; i < N; i++) {
            int have = sc.nextInt();
            int cap = sc.nextInt();
            nodes[i] = new Node(have, cap);
        }

        // Read the boss for each node
        for (int i = 1; i < N; i++) {
            bosses[i - 1] = sc.nextInt();
            nodes[i].parent = bosses[i - 1];
        }

        // Perform BFS traversal of the tree
        bfs(nodes, bosses, N);

        // Print the total amount present at the root node
        System.out.println(nodes[0].have);
    }
}

